import React, { useState, useMemo } from 'react';
import './AllUsers.css';

interface User {
  id: number;
  name: string;
  email: string;
  phone: string;
  city: string;
  planName: string;
  status: 'Active' | 'Inactive' | 'Pending';
  joinDate: string;
}

// Mock user data - moved outside component to prevent re-renders
const mockUsers: User[] = [
  {
